import"./common.min2.js";import"./watcher.min.js";import"./index.min2.js";import"./common.min.js";document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelector(".search-blog__input"),t=document.querySelector(".search-blog__clear");e.addEventListener("input",()=>{t.classList.toggle("active",e.value.length)}),t.addEventListener("click",()=>{e.value="",e.focus(),t.classList.remove("active")})});
